function contentstream (req, debug, inflate) {
  const encoding = (req.headers['content-encoding'] || 'identity').toLowerCase()
  const length = req.headers['content-length']

  debug('content-encoding "%s"', encoding)

  if (inflate === false && encoding !== 'identity') {
    throw createError(415, 'content encoding unsupported', {
      encoding: encoding,
      type: 'encoding.unsupported'
    })
  }

  if (encoding === 'identity') {
    req.length = length
    return req
  }

  const stream = createDecompressionStream(encoding, debug)
  req.pipe(stream)
  return stream
}

function getHeaderValueFromOptions(
  options: Readonly<StrictTransportSecurityOptions>,
): string {
  if ("maxage" in options) {
    throw new Error(
      "Strict-Transport-Security received an unsupported property, `maxage`. Did you mean to pass `maxAge`?",
    );
  }
  if ("includeSubdomains" in options) {
    throw new Error(
      'Strict-Transport-Security middleware should use `includeSubDomains` instead of `includeSubdomains`. (The correct one has an uppercase "D".)',
    );
  }

  const directives: string[] = [`max-age=${parseMaxAge(options.maxAge)}`];

  if (options.includeSubDomains === undefined || options.includeSubDomains) {
    directives.push("includeSubDomains");
  }

  if (options.preload) {
    directives.push("preload");
  }

  return directives.join("; ");
}

function json_hook(json) {
  let originalJson = json;
  res.json = original;
  if (res.headersSent) return res;
  if (!mungError && res.statusCode >= 500) return original.call(this, json);

  // Run the munger
  try {
    json = fn(json, req, res);
  } catch (e) {
    return mung.onError(e, req, res, next);
  }
  if (res.headersSent) return res;

  // If no returned value from fn, then assume json has been mucked with.
  if (json === undefined) json = originalJson;

  // If null, then 204 No Content
  if (json === null) return res.status(204).end();

  // If munged scalar value, then text/plain
  if (originalJson !== json && isScalar(json)) {
    res.set('content-type', 'text/plain');
    return res.send(String(json));
  }

  return original.call(this, json);
}

async function getClientAuth(config) {
  switch (config.clientAuthMethod) {
    case 'client_secret_basic':
      return client.ClientSecretBasic(config.clientSecret);
    case 'client_secret_post':
      return client.ClientSecretPost(config.clientSecret);
    case 'client_secret_jwt':
      return client.ClientSecretJwt(config.clientSecret);
    case 'private_key_jwt': {
      const privateKey = await importPrivateKey(
        config.clientAssertionSigningKey,
        config.clientAssertionSigningAlg,
      );
      return client.PrivateKeyJwt(privateKey);
    }
    case 'none':
      return client.None();
    default:
      // Default based on whether client_secret is present
      if (config.clientSecret) {
        return client.ClientSecretPost(config.clientSecret);
      }
      return client.None();
  }
}

function formatMessage(startupResult: BackendStartupResult): string {
  const parts: string[] = [
    'Backend startup failed due to the following errors:',
  ];
  const failures: string[] = [];

  for (const plugin of startupResult.plugins) {
    if (plugin.failure && !plugin.failure.allowed) {
      failures.push(
        `  Plugin '${plugin.pluginId}' startup failed; caused by ${plugin.failure.error}`,
      );
    }

    for (const mod of plugin.modules) {
      if (mod.failure && !mod.failure.allowed) {
        failures.push(
          `  Module '${mod.moduleId}' for plugin '${plugin.pluginId}' startup failed; caused by ${mod.failure.error}`,
        );
      }
    }
  }

  if (failures.length > 0) {
    parts.push(...failures);
  }

  return parts.join('\n');
}

function convertAwsCodeCommit(entries: Config[]): JsonObject[] {
  return entries.map(entry => {
    const auth: JsonObject[] = [];

    const accessKeyId = entry.getOptionalString('accessKeyId');
    const secretAccessKey = entry.getOptionalString('secretAccessKey');
    if (accessKeyId !== undefined && secretAccessKey !== undefined) {
      auth.push({ method: 'accessKey', accessKeyId, secretAccessKey });
    }

    const roleArn = entry.getOptionalString('roleArn');
    if (roleArn !== undefined) {
      auth.push(
        omitUndefined({
          method: 'assumeRole',
          roleArn,
          externalId: entry.getOptionalString('externalId'),
        }),
      );
    }

    const region = entry.getString('region');
    const host =
      entry.getOptionalString('host') ?? `${region}.console.aws.amazon.com`;

    return { type: 'aws-codecommit', host, region, auth };
  });
}

function createApplication() {
  var app = function(req, res, next) {
    app.handle(req, res, next);
  };

  mixin(app, EventEmitter.prototype, false);
  mixin(app, proto, false);

  // expose the prototype that will get set on requests
  app.request = Object.create(req, {
    app: { configurable: true, enumerable: true, writable: true, value: app }
  })

  // expose the prototype that will get set on responses
  app.response = Object.create(res, {
    app: { configurable: true, enumerable: true, writable: true, value: app }
  })

  app.init();
  return app;
}

module.exports = async (req, config) => {
  const store =
    (config.backchannelLogout && config.backchannelLogout.store) ||
    config.session.store;
  const get = safePromisify(store.get, store);
  const { serverMetadata } = await getClient(config);
  const issuer = serverMetadata.issuer;
  const { sid, sub } = req.oidc.idTokenClaims;
  if (!sid && !sub) {
    throw new Error(`The session must have a 'sid' or a 'sub'`);
  }
  const [logoutSid, logoutSub] = await Promise.all([
    sid && get(`${issuer}|${sid}`),
    sub && get(`${issuer}|${sub}`),
  ]);
  return !!(logoutSid || logoutSub);
};

singleCount(request: Request, store: Store, key: string) {
	let storeKeys = singleCountKeys.get(request)
	if (!storeKeys) {
		storeKeys = new Map()
		singleCountKeys.set(request, storeKeys)
	}

	const storeKey = store.localKeys ? store : store.constructor.name
	let keys = storeKeys.get(storeKey)
	if (!keys) {
		keys = []
		storeKeys.set(storeKey, keys)
	}

	const prefixedKey = `${store.prefix ?? ''}${key}`

	if (keys.includes(prefixedKey)) {
		throw new ValidationError(
			'ERR_ERL_DOUBLE_COUNT',
			`The hit count for ${key} was incremented more than once for a single request.`,
		)
	}

	keys.push(prefixedKey)
}

export function getControllerParameterMetadata(
  constructor: NewableFunction,
): ControllerParameterMetadata {
  const parameterMetadata: ControllerParameterMetadata = Reflect.getOwnMetadata(
    METADATA_KEY.controllerParameter,
    constructor,
  ) as ControllerParameterMetadata;

  const genericMetadata: ControllerParameterMetadata = Reflect.getMetadata(
    METADATA_KEY.controllerParameter,
    Reflect.getPrototypeOf(constructor) as NewableFunction,
  ) as ControllerParameterMetadata;

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  if (genericMetadata !== undefined && parameterMetadata !== undefined) {
    return { ...parameterMetadata, ...genericMetadata };
  }
  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
  if (genericMetadata !== undefined) {
    return genericMetadata;
  }
  return parameterMetadata;
}

function _onNext(error, doc) {
  if (error) {
    return this.callback(error);
  }
  if (!doc) {
    this.ctx._batchExhausted = true;
    return _populateBatch.call(this);
  }

  this.ctx._batchDocs.push(doc);

  if (this.ctx._batchDocs.length < this.ctx.options._populateBatchSize) {
    // If both `batchSize` and `_populateBatchSize` are huge, calling `next()` repeatedly may
    // cause a stack overflow. So make sure we clear the stack.
    immediate(() => this.ctx.cursor.next().then(
      res => { _onNext.call(this, null, res); },
      err => { _onNext.call(this, err); }
    ));
  } else {
    _populateBatch.call(this);
  }
}

export function augmentAjvErrors(errors: ErrorObject[] = []): ErrorObject[] {
  errors.forEach((e) => {
    if (e.keyword === 'enum') {
      const params: any = e.params;
      const allowedEnumValues = params?.allowedValues;
      e.message = !!allowedEnumValues
        ? `${e.message}: ${allowedEnumValues.join(', ')}`
        : e.message;
    }
  });
  const serDesPaths = new Set<string>();
  return errors.filter((e) => {
    if (serDesPaths.has(e.schemaPath)) {
      return false;
    }
    if (e.params['x-eov-res-serdes']) {
      // If response serialization failed,
      // silence additional errors about not being a string.
      serDesPaths.add(e.schemaPath.replace('x-eov-res-serdes', 'x-eov-type'));
    }
    return true;
  });
}

async function transform(root: SgRoot<Js>): Promise<string | null> {
  const rootNode = root.root()

  const nodes = rootNode.findAll({
    rule: {
      pattern: '$OBJ.$METHOD($$$METHOD)',
    },
    constraints: {
      METHOD: { regex: '^(sendfile)$' },
    },
  })

  if (!nodes.length) return null

  const edits: Edit[] = []

  for (const call of nodes) {
    const method = call.getMatch('METHOD')
    const obj = call.getMatch('OBJ')
    if (!method || !obj) continue

    const objDef = obj.definition({ resolveExternal: false })
    if (!objDef) continue

    edits.push(method.replace('sendFile'))
  }

  if (!edits.length) return null
  return rootNode.commitEdits(edits)
}

function responseTime (options) {
  var opts = options || {}

  if (typeof options === 'number') {
    // back-compat single number argument
    deprecate('number argument: use {digits: ' + JSON.stringify(options) + '} instead')
    opts = { digits: options }
  }

  // get the function to invoke
  var fn = typeof opts !== 'function'
    ? createSetHeader(opts)
    : opts

  return function responseTime (req, res, next) {
    var startAt = process.hrtime()

    onHeaders(res, function onHeaders () {
      var diff = process.hrtime(startAt)
      var time = diff[0] * 1e3 + diff[1] * 1e-6

      fn(req, res, time)
    })

    next()
  }
}

function _handlePreHookError(queryCursor, err) {
  if (err instanceof kareem.skipWrappedFunction) {
    const resultValue = err.args[0];
    if (resultValue != null && (!Array.isArray(resultValue) || resultValue.length)) {
      const err = new MongooseError(
        'Cannot `skipMiddlewareFunction()` with a value when using ' +
        '`.aggregate().cursor()`, value must be nullish or empty array, got "' +
        util.inspect(resultValue) +
        '".'
      );
      queryCursor._markError(err);
      queryCursor.listeners('error').length > 0 && queryCursor.emit('error', err);
      return;
    }
    queryCursor.emit('cursor', null);
    return;
  }
  queryCursor._markError(err);
  queryCursor.listeners('error').length > 0 && queryCursor.emit('error', err);
}

function createStrictSyntaxError (str, char) {
  const index = str.indexOf(char)
  let partial = ''

  if (index !== -1) {
    partial = str.substring(0, index) + JSON_SYNTAX_CHAR.repeat(str.length - index)
  }

  try {
    JSON.parse(partial); /* istanbul ignore next */ throw new SyntaxError('strict violation')
  } catch (e) {
    return normalizeJsonSyntaxError(e, {
      message: e.message.replace(JSON_SYNTAX_REGEXP, function (placeholder) {
        return str.substring(index, index + placeholder.length)
      }),
      stack: e.stack
    })
  }
}

View.prototype.render = function render(options, callback) {
  var sync = true;

  debug('render "%s"', this.path);

  // render, normalizing sync callbacks
  this.engine(this.path, options, function onRender() {
    if (!sync) {
      return callback.apply(this, arguments);
    }

    // copy arguments
    var args = new Array(arguments.length);
    var cntx = this;

    for (var i = 0; i < arguments.length; i++) {
      args[i] = arguments[i];
    }

    // force callback to be async
    return process.nextTick(function renderTick() {
      return callback.apply(cntx, args);
    });
  });

  sync = false;
};

function completeOne(model, doc, res, options, fields, userProvidedFields, pop, callback) {
  if (options.includeResultMetadata && doc == null) {
    _init(null);
    return null;
  }

  helpers.createModelAndInit(model, doc, fields, userProvidedFields, options, pop, _init);

  function _init(err, casted) {
    if (err) {
      return callback(err);
    }


    if (options.includeResultMetadata) {
      if (doc && casted) {
        if (options.session != null) {
          casted.$session(options.session);
        }
        res.value = casted;
      } else {
        res.value = null;
      }
      return callback(null, res);
    }
    if (options.session != null) {
      casted.$session(options.session);
    }
    callback(null, casted);
  }
}
